```typescript
"use client";

import { useEffect, useRef } from "react";

interface Neuron {
  layer: number;
  idx: number;
  x: number;
  y: number;
  activation: number;
  gradient: number;
  dropout: boolean;
  dropoutTimer: number;
}

interface Connection {
  fromIdx: number;  // index into neurons array
  toIdx: number;
  weight: number;
  flash: number;    // transient highlight from pulses
}

interface SkipLink {
  fromIdx: number;
  toIdx: number;
  weight: number;
  flash: number;
}

interface AttentionLink {
  aIdx: number;
  bIdx: number;
  strength: number;
}

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;
    let start = performance.now();

    const TAU = Math.PI * 2;
    const layerSizes = [5, 9, 11, 9, 5];
    const numLayers = layerSizes.length;
    const attentionLayer = 2;

    let neurons: Neuron[] = [];
    let connections: Connection[] = [];
    let skipLinks: SkipLink[] = [];
    let attentionLinks: AttentionLink[] = [];

    let epoch = 0;
    let lastEpochProgress = 0;
    let loss = 1.0;
    let lossHistory: number[] = [];
    const maxLossHistory = 80;

    const buildNetwork = () => {
      neurons = [];
      connections = [];
      skipLinks = [];
      attentionLinks = [];

      const padX = Math.max(60, width * 0.06);
      const padTop = 50;
      const padBottom = 70; // space for loss graph
      const usableW = width - padX * 2;
      const usableH = height - padTop - padBottom;

      const layerXs: number[] = [];
      for (let i = 0; i < numLayers; i++) {
        layerXs.push(padX + (usableW * i) / (numLayers - 1));
      }

      for (let l = 0; l < numLayers; l++) {
        const n = layerSizes[l];
        const spacing = usableH / Math.max(1, n);
        for (let i = 0; i < n; i++) {
          neurons.push({
            layer: l,
            idx: i,
            x: layerXs[l],
            y: padTop + spacing * (i + 0.5),
            activation: 0,
            gradient: 0,
            dropout: false,
            dropoutTimer: 0,
          });
        }
      }

      const idx = (l: number, i: number) => {
        let res = 0;
        for (let ll = 0; ll < l; ll++) res += layerSizes[ll];
        return res + i;
      };

      // Regular connections
      for (let l = 0; l < numLayers - 1; l++) {
        for (let i = 0; i < layerSizes[l]; i++) {
          for (let j = 0; j < layerSizes[l + 1]; j++) {
            connections.push({
              fromIdx: idx(l, i),
              toIdx: idx(l + 1, j),
              weight: (Math.random() * 2 - 1) * 0.8,
              flash: 0,
            });
          }
        }
      }

      // Skip connections (residual blocks): 0→2, 1→3, 2→4
      const skipPairs: [number, number][] = [[0, 2], [1, 3], [2, 4]];
      for (const [a, b] of skipPairs) {
        const count = Math.min(3, layerSizes[a]);
        for (let i = 0; i < count; i++) {
          const fromIdx = Math.floor((i + 0.5) * layerSizes[a] / count);
          const toIdx = Math.floor((i + 0.5) * layerSizes[b] / count);
          skipLinks.push({
            fromIdx: idx(a, fromIdx),
            toIdx: idx(b, toIdx),
            weight: 0.4 + Math.random() * 0.3,
            flash: 0,
          });
        }
      }

      // Attention links within layer 2
      const attN = layerSizes[attentionLayer];
      for (let i = 0; i < attN; i++) {
        for (let j = i + 1; j < attN; j++) {
          if (Math.random() < 0.25) {
            attentionLinks.push({
              aIdx: idx(attentionLayer, i),
              bIdx: idx(attentionLayer, j),
              strength: Math.random(),
            });
          }
        }
      }
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(380, Math.max(280, Math.floor(window.innerHeight * 0.38)));

      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);

