```typescript
"use client";

import { useEffect, useRef } from "react";

interface Neuron {
  layer: number;
  idx: number;
  x: number;
  y: number;
  activation: number;
  gradient: number;
  dropout: boolean;
}

interface Connection {
  from: Neuron;
  to: Neuron;
  weight: number;
  targetWeight: number;
}

interface SkipLink {
  from: Neuron;
  to: Neuron;
  weight: number;
}

interface Pulse {
  // traveling pulse along a path
  fromX: number;
  fromY: number;
  toX: number;
  toY: number;
  progress: number;  // 0 to 1
  speed: number;
  color: "forward" | "backward";
  alive: boolean;
}

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;
    let start = performance.now();

    // Network configuration
    const layerSizes = [5, 8, 10, 8, 5];
    const attentionLayer = 2;

    let neurons: Neuron[] = [];
    let connections: Connection[] = [];
    let skipLinks: SkipLink[] = [];
    let attentionLinks: { a: Neuron; b: Neuron }[] = [];

    // Training state
    let epoch = 0;
    let epochProgress = 0; // 0-1 within an epoch
    let loss = 1.0;
    let lossHistory: number[] = [];
    let trainingRun = 0;

    // Layout
    let layerXs: number[] = [];
    let layerYs: number[][] = []; // y positions per layer

    const buildNetwork = () => {
      neurons = [];
      connections = [];
      skipLinks = [];
      attentionLinks = [];

      const padX = 80;
      const padY = 60;
      const usableW = width - padX * 2;
      const usableH = height - padY * 2 - 40; // reserve 40px at bottom for loss graph

      layerXs = [];
      for (let i = 0; i < layerSizes.length; i++) {
        layerXs.push(padX + (usableW * i) / (layerSizes.length - 1));
      }

      layerYs = [];
      for (let l = 0; l < layerSizes.length; l++) {
        const n = layerSizes[l];
        const ys: number[] = [];
        const layerH = usableH;
        const spacing = layerH / Math.max(1, n);
        for (let i = 0; i < n; i++) {
          ys.push(padY + spacing * (i + 0.5));
        }
        layerYs.push(ys);
      }

      // Create neurons
      for (let l = 0; l < layerSizes.length; l++) {
        for (let i = 0; i < layerSizes[l]; i++) {
          neurons.push({
            layer: l,
            idx: i,
            x: layerXs[l],
            y: layerYs[l][i],
            activation: 0,
            gradient: 0,
            dropout: false,
          });
        }
      }

      const getNeuron = (l: number, i: number) => neurons.find(n => n.layer === l && n.idx === i)!;

      // Create connections (all-to-all between adjacent layers)
      for (let l = 0; l < layerSizes.length - 1; l++) {
        for (let i = 0; i < layerSizes[l]; i++) {
          for (let j = 0; j < layerSizes[l + 1]; j++) {
            const w = (Math.random() * 2 - 1) * 0.8;
            connections.push({
              from: getNeuron(l, i),
              to: getNeuron(l + 1, j),
              weight: w,
              targetWeight: w,
            });
          }
        }
      }

      // Skip connections (residual): layer 0→2, 1→3, 2→4
      const skipPairs = [[0, 2], [1, 3], [2, 4]];
      for (const [a, b] of skipPairs) {
        // Only connect a few representative neurons
        const count = Math.min(4, layerSizes[a]);
        for (let i = 0; i < count; i++) {
          const fromIdx = Math.floor(i * layerSizes[a] / count);
          const toIdx = Math.floor(i * layerSizes[b] / count);
          skipLinks.push({
            from: getNeuron(a, fromIdx),
            to: getNeuron(b, toIdx),
            weight: 0.5 + Math.random() * 0.3,
          });
        }
      }

      // Attention links within layer 2
      const attN = layerSizes[attentionLayer];
      for (let i = 0; i < attN; i++) {
        for (let j = i + 1; j < attN; j++) {
          if (Math.random() < 0.3) {
            attentionLinks.push({
              a: getNeuron(attentionLayer, i),
              b: getNeuron(attentionLayer, j),
            });
          }
        }
      }
    };

    const resetTrainingRun = () => {
      trainingRun++;
      epoch = 0;
      loss = 0.8 + Math.random() * 0.4;
      lossHistory = [];
      // Re-randomize weights
      for (const c of connections) {
        c.weight = (Math.random() * 2 - 1) * 0.8;
        c.targetWeight = c.weight;
      }
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(360, Math.max(260, Math.floor(window.innerHeight * 0.36)));

      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);

      buildNetwork();
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    // ... draw function
  });
}
```

