  toIdx: number;
  weight: number;
  flash: number;
}

interface AttentionLink {
  aIdx: number;
  bIdx: number;
  strength: number;
}

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;
    let start = performance.now();

    const TAU = Math.PI * 2;
    const layerSizes = [5, 9, 11, 9, 5];
    const numLayers = layerSizes.length;
    const attentionLayer = 2;

    let neurons: Neuron[] = [];
    let connections: Connection[] = [];
    let skipLinks: SkipLink[] = [];
    let attentionLinks: AttentionLink[] = [];

    let epoch = 0;
    let lastEpochProgress = 0;
    let loss = 1.0;
    let lossHistory: number[] = [];
    const maxLossHistory = 80;

    const buildNetwork = () => {
      neurons = [];
      connections = [];
      skipLinks = [];
      attentionLinks = [];

      const padX = Math.max(60, width * 0.06);
      const padTop = 50;
      const padBottom = 70; // space for loss graph
      const usableW = width - padX * 2;
      const usableH = height - padTop - padBottom;

      const layerXs: number[] = [];
      for (let i = 0; i < numLayers; i++) {
        layerXs.push(padX + (usableW * i) / (numLayers - 1));
      }

      for (let l = 0; l < numLayers; l++) {
        const n = layerSizes[l];
        const spacing = usableH / Math.max(1, n);
        for (let i = 0; i < n; i++) {
          neurons.push({
            layer: l,
            idx: i,
            x: layerXs[l],
            y: padTop + spacing * (i + 0.5),
            activation: 0,
            gradient: 0,
            dropout: false,
            dropoutTimer: 0,
          });
        }
      }

      const idx = (l: number, i: number) => {
        let res = 0;
        for (let ll = 0; ll < l; ll++) res += layerSizes[ll];
        return res + i;
      };

      // Regular connections
      for (let l = 0; l < numLayers - 1; l++) {
        for (let i = 0; i < layerSizes[l]; i++) {
          for (let j = 0; j < layerSizes[l + 1]; j++) {
            connections.push({
              fromIdx: idx(l, i),
              toIdx: idx(l + 1, j),
              weight: (Math.random() * 2 - 1) * 0.8,
              flash: 0,
            });
          }
        }
      }

      // Skip connections (residual blocks): 0→2, 1→3, 2→4
      const skipPairs: [number, number][] = [[0, 2], [1, 3], [2, 4]];
      for (const [a, b] of skipPairs) {
        const count = Math.min(3, layerSizes[a]);
        for (let i = 0; i < count; i++) {
          const fromIdx = Math.floor((i + 0.5) * layerSizes[a] / count);
          const toIdx = Math.floor((i + 0.5) * layerSizes[b] / count);
          skipLinks.push({
            fromIdx: idx(a, fromIdx),
            toIdx: idx(b, toIdx),
            weight: 0.4 + Math.random() * 0.3,
            flash: 0,
          });
        }
      }

      // Attention links within layer 2
      const attN = layerSizes[attentionLayer];
      for (let i = 0; i < attN; i++) {
        for (let j = i + 1; j < attN; j++) {
          if (Math.random() < 0.25) {
            attentionLinks.push({
              aIdx: idx(attentionLayer, i),
              bIdx: idx(attentionLayer, j),
              strength: Math.random(),
            });
          }
        }
      }
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(380, Math.max(280, Math.floor(window.innerHeight * 0.38)));

      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);

      buildNetwork();
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    const draw = (now: number) => {
      const t = (now - start) * 0.001;

      // Trail fade
      ctx.fillStyle = "rgba(0, 0, 0, 0.14)";
      ctx.fillRect(0, 0, width, height);

      // Training cycle
      const epochDuration = 2.2;
      const epochProgress = (t % epochDuration) / epochDuration;

      if (epochProgress < lastEpochProgress) {
        epoch++;
        // Simulate loss decrease
        const baseLoss = 0.9 * Math.exp(-epoch / 12) + 0.04;
        loss = baseLoss + (Math.random() - 0.5) * 0.08 * Math.exp(-epoch / 20);
        loss = Math.max(0.02, loss);
        lossHistory.push(loss);
        if (lossHistory.length > maxLossHistory) lossHistory.shift();

        // Weight drift (simulating gradient updates)
        const lr = 0.15 * Math.exp(-epoch / 25); // learning rate decay
        for (const c of connections) {
          c.weight += (Math.random() - 0.5) * lr * 0.5;
          c.weight = Math.max(-1, Math.min(1, c.weight));
        }
        for (const s of skipLinks) {
          s.weight += (Math.random() - 0.5) * lr * 0.3;
          s.weight = Math.max(-1, Math.min(1, s.weight));
        }

        // Occasionally toggle dropout
        if (epoch > 3 && Math.random() < 0.3) {
          const n = neurons[Math.floor(Math.random() * neurons.length)];
          if (n.layer > 0 && n.layer < numLayers - 1) {
            n.dropout = true;
            n.dropoutTimer = 1;
          }
        }

        // Reset training run after convergence
        if (epoch > 55) {
          epoch = 0;
          loss = 0.8 + Math.random() * 0.3;
          lossHistory = [];
          for (const c of connections) {
            c.weight = (Math.random() * 2 - 1) * 0.8;
          }
        }
      }
      lastEpochProgress = epochProgress;

      // Forward pass: 0 to 0.42
      // Loss flash: 0.42 to 0.50
      // Backward pass: 0.50 to 0.92
      // Weight update: 0.92 to 1.0

      const forwardWave = epochProgress < 0.42 
        ? (epochProgress / 0.42) * (numLayers - 1) 
        : -1;
      const backwardWave = epochProgress >= 0.50 && epochProgress < 0.92
        ? (numLayers - 1) - ((epochProgress - 0.50) / 0.42) * (numLayers - 1)
        : -1;
      const isWeightUpdate = epochProgress >= 0.92;

      // Update neurons
      for (const n of neurons) {
        if (n.dropout) {
          n.dropoutTimer -= 0.02;
          if (n.dropoutTimer <= 0) n.dropout = false;
        }

        if (forwardWave >= 0 && !n.dropout) {
          const dist = Math.abs(n.layer - forwardWave);
          if (dist < 0.6) {
            n.activation = Math.max(n.activation, (1 - dist / 0.6) * (0.6 + Math.random() * 0.4));
          }
        }
        n.activation *= 0.90;

        if (backwardWave >= 0) {
          const dist = Math.abs(n.layer - backwardWave);
          if (dist < 0.6) {
            n.gradient = Math.max(n.gradient, (1 - dist / 0.6) * (0.5 + Math.random() * 0.5));
          }
        }
        n.gradient *= 0.90;
      }

      // Update connection flash
      for (const c of connections) c.flash *= 0.88;
      for (const s of skipLinks) s.flash *= 0.88;

      // Set flash for connections at the wave front
      if (forwardWave >= 0) {
        const waveLayer = Math.floor(forwardWave + 0.5);
        // Flash connections between floor(wave) and ceil(wave)
        for (const c of connections) {
          const fromLayer = neurons[c.fromIdx].layer;
          if (fromLayer === Math.floor(forwardWave) && forwardWave - Math.floor(forwardWave) < 0.8) {
            c.flash = Math.max(c.flash, 1 - (forwardWave - fromLayer));
          }
        }
      }
      if (backwardWave >= 0) {
        for (const c of connections) {
          const toLayer = neurons[c.toIdx].layer;
          if (toLayer === Math.ceil(backwardWave) && Math.ceil(backwardWave) - backwardWave < 0.8) {
            c.flash = Math.max(c.flash, 1 - (Math.ceil(backwardWave) - backwardWave));
          }
        }
      }

      // ===== DRAW =====

      // 1. Draw regular connections (base layer, very faint)
      for (const c of connections) {
        const from = neurons[c.fromIdx];
        const to = neurons[c.toIdx];
        const wMag = Math.abs(c.weight);
        const baseAlpha = 0.025 + wMag * 0.05;
        const isWeightUpdateFlash = isWeightUpdate ? Math.random() * 0.15 : 0;

        // Color: positive = cool, negative = warm
        const hue = c.weight >= 0 ? 210 : 20;
        const sat = 30;
        const lum = 45 + wMag * 15;
        const alpha = baseAlpha + c.flash * 0.4 + isWeightUpdateFlash;

        ctx.strokeStyle = `hsla(${hue}, ${sat}%, ${lum}%, ${alpha})`;
        ctx.lineWidth = 0.4 + wMag * 0.8 + c.flash * 0.8;
        ctx.beginPath();
        ctx.moveTo(from.x, from.y);
        ctx.lineTo(to.x, to.y);
        ctx.stroke();
      }

      // 2. Draw attention links (thin curves with pulsing)
      for (let i = 0; i < attentionLinks.length; i++) {
        const a = attentionLinks[i];
        const na = neurons[a.aIdx];
        const nb = neurons[a.bIdx];
        const pulse = 0.3 + 0.7 * (0.5 + 0.5 * Math.sin(t * 2 + i * 1.7 + a.strength * 5));
        const alpha = 0.04 + pulse * 0.08 * a.strength;

        // Curved line (slight bow)
        const mx = (na.x + nb.x) / 2 + 15;
        const my = (na.y + nb.y) / 2;
        ctx.strokeStyle = `hsla(270, 40%, 60%, ${alpha})`;
        ctx.lineWidth = 0.4;
        ctx.beginPath();
        ctx.moveTo(na.x, na.y);
        ctx.quadraticCurveTo(mx, my, nb.x, nb.y);
        ctx.stroke();
      }

      // 3. Draw skip connections (curved arcs)
      for (const s of skipLinks) {
        const from = neurons[s.fromIdx];
        const to = neurons[s.toIdx];
        const wMag = Math.abs(s.weight);
        const baseAlpha = 0.08 + wMag * 0.06;
        const alpha = baseAlpha + s.flash * 0.5;

        // Curve above the network
        const midX = (from.x + to.x) / 2;
        const archHeight = 25 + Math.abs(to.x - from.x) * 0.15;
        const midY = Math.min(from.y, to.y) - archHeight;

        ctx.strokeStyle = `hsla(200, 15%, 75%, ${alpha})`;
        ctx.lineWidth = 0.5 + wMag * 0.5 + s.flash * 1.0;
        ctx.setLineDash([3, 4]);
        ctx.beginPath();
        ctx.moveTo(from.x, from.y);
        ctx.quadraticCurveTo(midX, midY, to.x, to.y);
        ctx.stroke();
        ctx.setLineDash([]);
      }

      // 4. Draw forward pulses (bright dots traveling along connections)
      if (forwardWave >= 0) {
        const layerF = Math.floor(forwardWave);
        const localProg = forwardWave - layerF;
        if (layerF < numLayers - 1) {
          // Draw pulses on connections between layerF and layerF+1
          // Select a subset for visual clarity
          const relevant = connections.filter(c => neurons[c.fromIdx].layer === layerF);
          for (const c of relevant) {
            if (Math.abs(c.weight) < 0.15) continue; // skip weak connections
            const from = neurons[c.fromIdx];
            const to = neurons[c.toIdx];
            const px = from.x + (to.x - from.x) * localProg;
            const py = from.y + (to.y - from.y) * localProg;
            const alpha = 0.6 * Math.abs(c.weight);
            ctx.fillStyle = `hsla(195, 70%, 75%, ${alpha})`;
            ctx.beginPath();
            ctx.arc(px, py, 1.2 + Math.abs(c.weight) * 0.8, 0, TAU);
            ctx.fill();
          }
        }
        // Also pulses on skip connections
        for (const s of skipLinks) {
          const from = neurons[s.fromIdx];
          const to = neurons[s.toIdx];
          const fromLayer = from.layer;
          const toLayer = to.layer;
          if (forwardWave >= fromLayer && forwardWave <= toLayer) {
            const prog = (forwardWave - fromLayer) / (toLayer - fromLayer);
            // Position along quadratic bezier
            const midX = (from.x + to.x) / 2;
            const archHeight = 25 + Math.abs(to.x - from.x) * 0.15;
            const midY = Math.min(from.y, to.y) - archHeight;
            const px = (1-prog)*(1-prog)*from.x + 2*(1-prog)*prog*midX + prog*prog*to.x;
            const py = (1-prog)*(1-prog)*from.y + 2*(1-prog)*prog*midY + prog*prog*to.y;
            ctx.fillStyle = `hsla(195, 80%, 80%, 0.7)`;
            ctx.beginPath();
            ctx.arc(px, py, 1.5, 0, TAU);
            ctx.fill();
          }
        }
      }

      // 5. Draw backward pulses (warm dots traveling backward)
      if (backwardWave >= 0) {
        const layerC = Math.ceil(backwardWave);
        const localProg = layerC - backwardWave; // 0 at start of segment, 1 at end
        const layerFrom = layerC; // output side
        const layerTo = layerC - 1; // input side
        if (layerTo >= 0) {
          const relevant = connections.filter(c => neurons[c.toIdx].layer === layerC);
          for (const c of relevant) {
            if (Math.abs(c.weight) < 0.15) continue;
            const from = neurons[c.fromIdx]; // input side (left)
            const to = neurons[c.toIdx];     // output side (right)
            // Backward: travel from 'to' to 'from'
            const px = to.x + (from.x - to.x) * localProg;
            const py = to.y + (from.y - to.y) * localProg;
            const alpha = 0.5 * Math.abs(c.weight);
            ctx.fillStyle = `hsla(30, 80%, 70%, ${alpha})`;
            ctx.beginPath();
            ctx.arc(px, py, 1.0 + Math.abs(c.weight) * 0.7, 0, TAU);
            ctx.fill();
          }
        }
        // Backward pulses on skip connections
        for (const s of skipLinks) {
          const from = neurons[s.fromIdx]; // left
          const to = neurons[s.toIdx];     // right
          const fromLayer = from.layer;
          const toLayer = to.layer;
          if (backwardWave <= toLayer && backwardWave >= fromLayer) {
            const prog = (toLayer - backwardWave) / (toLayer - fromLayer);
            const midX = (from.x + to.x) / 2;
            const archHeight = 25 + Math.abs(to.x - from.x) * 0.15;
            const midY = Math.min(from.y, to.y) - archHeight;
            const px = (1-prog)*(1-prog)*from.x + 2*(1-prog)*prog*midX + prog*prog*to.x;
            const py = (1-prog)*(1-prog)*from.y + 2*(1-prog)*prog*midY + prog*prog*to.y;
            ctx.fillStyle = `hsla(30, 85%, 72%, 0.6)`;
            ctx.beginPath();
            ctx.arc(px, py, 1.3, 0, TAU);
            ctx.fill();
          }
        }
      }

      // 6. Draw neurons
      for (const n of neurons) {
        if (n.dropout) {
          // Draw dimmed neuron with X
          ctx.strokeStyle = `hsla(0, 0%, 30%, 0.4)`;
          ctx.lineWidth = 0.5;
          ctx.beginPath();
          ctx.arc(n.x, n.y, 3, 0, TAU);
          ctx.stroke();
          continue;
        }

        const act = n.activation;
        const grad = n.gradient;
        const baseR = 2.5;
        const r = baseR + act * 2.5 + grad * 1.5;

        // Glow
        if (act > 0.1 || grad > 0.1) {
          const glowR = r * 3;
          const grad2 = ctx.createRadialGradient(n.x, n.y, 0, n.x, n.y, glowR);
          if (act > grad) {
            grad2.addColorStop(0, `hsla(195, 70%, 70%, ${act * 0.3})`);
            grad2.addColorStop(1, `hsla(195, 70%, 70%, 0)`);
          } else {
            grad2.addColorStop(0, `hsla(30, 80%, 65%, ${grad * 0.3})`);
            grad2.addColorStop(1, `hsla(30, 80%, 65%, 0)`);
          }
          ctx.fillStyle = grad2;
          ctx.beginPath();
          ctx.arc(n.x, n.y, glowR, 0, TAU);
          ctx.fill();
        }

        // Core
        const hue = act > grad ? 195 : 30;
        const sat = act > grad ? 60 : 75;
        const lum = 40 + Math.max(act, grad) * 35;
        const alpha = 0.5 + Math.max(act, grad) * 0.5;
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${lum}%, ${alpha})`;
        ctx.beginPath();
        ctx.arc(n.x, n.y, r, 0, TAU);
        ctx.fill();

        // Specular highlight for bright neurons
        if (act > 0.5) {
          ctx.fillStyle = `hsla(195, 30%, 95%, ${act * 0.4})`;
          ctx.beginPath();
          ctx.arc(n.x, n.y, r * 0.35, 0, TAU);
          ctx.fill();
        }
      }

      // 7. Loss flash at output when forward pass completes
      if (epochProgress >= 0.42 && epochProgress < 0.48) {
        const flashAlpha = (1 - (epochProgress - 0.42) / 0.06) * 0.15;
        const outputX = layerXs[numLayers - 1];
        // Actually layerXs is local to buildNetwork... need to store it
        // Let me handle this differently
      }

      // 8. Draw loss graph (bottom right)
      const graphW = 80;
      const graphH = 30;
      const graphX = width - graphW - 20;
      const graphY = height - graphH - 15;

      // Graph background
      ctx.fillStyle = "rgba(255, 255, 255, 0.03)";
      ctx.fillRect(graphX, graphY, graphW, graphH);
      ctx.strokeStyle = "rgba(255, 255, 255, 0.08)";
      ctx.lineWidth = 0.5;
      ctx.strokeRect(graphX, graphY, graphW, graphH);

      // Loss curve
      if (lossHistory.length > 1) {
        ctx.strokeStyle = "hsla(150, 60%, 55%, 0.7)";
        ctx.lineWidth = 1;
        ctx.beginPath();
        for (let i = 0; i < lossHistory.length; i++) {
          const x = graphX + (i / (maxLossHistory - 1)) * graphW;
          const y = graphY + graphH - lossHistory[i] * graphH;
          if (i === 0) ctx.moveTo(x, y);
          else ctx.lineTo(x, y);
        }
        ctx.stroke();
      }

      // Labels
      ctx.fillStyle = "rgba(255, 255, 255, 0.35)";
      ctx.font = "10px monospace";
      ctx.textAlign = "left";
      ctx.fillText(`epoch ${epoch}`, 20, height - 25);
      ctx.fillText(`loss ${loss.toFixed(3)}`, 20, height - 12);

      ctx.textAlign = "right";
      ctx.fillText("loss", width - graphW - 25, graphY + graphH / 2 + 3);

      animationId = requestAnimationFrame(draw);
    };

    // Need to store layerXs for use in draw
    let layerXs: number[] = [];

    resize();
    start = performance.now();
    window.addEventListener("resize", debouncedResize);
    animationId = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener("resize", debouncedResize);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed inset-x-0 top-0 z-0"
      style={{ display: "block" }}
    />
  );
}
