"use client";

import { useEffect, useRef } from "react";

interface Node {
  layer: number;
  idx: number;
  x: number;
  y: number;
  activation: number;
  pulse: number;
  isAttention: boolean;
}

interface Edge {
  from: number;
  to: number;
  weight: number;
  targetWeight: number;
  residual: boolean;
  attention: boolean;
  x1: number; y1: number; x2: number; y2: number;
  len: number;
  // control point for curved residual/attention edges
  cx: number; cy: number;
}

interface Particle {
  edgeIdx: number;
  t: number;
  speed: number;
  size: number;
  forward: boolean;
  warm: boolean;
}

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;
    let start = performance.now();

    // Network architecture: residual MLP with a self-attention layer.
    const LAYER_SIZES = [4, 7, 9, 7, 3];
    const ATTENTION_LAYER = 2; // index of self-attention layer

    let nodes: Node[] = [];
    let edges: Edge[] = [];
    let particles: Particle[] = [];
    let layerNodeIndexRanges: Array<[number, number]> = []; // [start, end) in nodes array

    // Training state
    let epoch = 0;
    let phase: "forward" | "backward" | "update" = "forward";
    let phaseT = 0; // 0..1 within phase
    const FORWARD_DUR = 1.8;
    const BACKWARD_DUR = 1.8;
    const UPDATE_DUR = 0.5;
    let waveLayer = 0; // current wave front layer
    let lastWaveLayer = -1;
    let loss = 2.4;
    let lossHistory: number[] = [];
    let maxLossHistory = 80;

    const buildNetwork = () => {
      nodes = [];
      edges = [];
      const L = LAYER_SIZES.length;
      const marginX = width * 0.08;
      const usableW = width - marginX * 2;
      const cy = height * 0.5;
      const usableH = height * 0.7;
      const layerSpacing = usableW / (L - 1);

      let idx = 0;
      for (let l = 0; l < L; l++) {
        const startIdx = idx;
        const count = LAYER_SIZES[l];
        const lx = marginX + l * layerSpacing;
        const spread = usableH * (0.6 + 0.4 * (count / LAYER_SIZES[2]));
        for (let i = 0; i < count; i++) {
          const t = count === 1 ? 0.5 : i / (count - 1);
          const y = cy - spread / 2 + t * spread;
          nodes.push({
            layer: l, idx: i, x: lx, y,
            activation: 0, pulse: 0,
            isAttention: l === ATTENTION_LAYER,
          });
          idx++;
        }
        layerNodeIndexRanges[l] = [startIdx, idx];
      }

      // Dense edges between consecutive layers
      for (let l = 0; l < L - 1; l++) {
        const [s1, e1] = layerNodeIndexRanges[l];
        const [s2, e2] = layerNodeIndexRanges[l + 1];
        for (let a = s1; a < e1; a++) {
          for (let b = s2; b < e2; b++) {
            addEdge(a, b, false, false);
          }
        }
      }
      // Residual skip connections (skip one layer)
      for (let l = 0; l < L - 2; l++) {
        const [s1, e1] = layerNodeIndexRanges[l];
        const [s2, e2] = layerNodeIndexRanges[l + 2];
        // connect a few pairs, not all (to limit count)
        const pairs = Math.min(3, e1 - s1);
        for (let k = 0; k < pairs; k++) {
          const a = s1 + Math.floor((k + 0.5) * (e1 - s1) / pairs);
          const b = s2 + Math.floor((k + 0.5) * (e2 - s2) / pairs);
          addEdge(a, b, true, false);
        }
      }
      // Self-attention within attention layer: each node to 2 neighbors
      const [sa, ea] = layerNodeIndexRanges[ATTENTION_LAYER];
      const count = ea - sa;
      for (let i = sa; i < ea; i++) {
        for (let d = 1; d <= 2; d++) {
          const j = sa + ((i - sa + d) % count);
          addEdge(i, j, false, true);
        }
      }

      // compute edge geometry & control points
      for (const e of edges) {
        const n1 = nodes[e.from];
        const n2 = nodes[e.to];
        e.x1 = n1.x; e.y1 = n1.y; e.x2 = n2.x; e.y2 = n2.y;
        e.len = Math.hypot(e.x2 - e.x1, e.y2 - e.y1);
        if (e.residual) {
          // arc above
          const mx = (e.x1 + e.x2) / 2;
          const my = (e.y1 + e.y2) / 2;
          const lift = -height * 0.35;
          e.cx = mx;
          e.cy = my + lift;
        } else if (e.attention) {
          // arc below
          const mx = (e.x1 + e.x2) / 2;
          const my = (e.y1 + e.y2) / 2;
          const drop = height * 0.12;
          e.cx = mx;
          e.cy = my + drop;
        } else {
          e.cx = (e.x1 + e.x2) / 2;
          e.cy = (e.y1 + e.y2) / 2;
        }
      }
    };

    const addEdge = (from: number, to: number, residual: boolean, attention: boolean) => {
      const w = (Math.random() * 2 - 1) * 0.6;
      edges.push({
        from, to,
        weight: w,
        targetWeight: w,
        residual, attention,
        x1: 0, y1: 0, x2: 0, y2: 0, len: 1,
        cx: 0, cy: 0,
      });
    };

    // Quadratic bezier point
    const bezier = (e: Edge, t: number) => {
      const mt = 1 - t;
      const x = mt * mt * e.x1 + 2 * mt * t * e.cx + t * t * e.x2;
      const y = mt * mt * e.y1 + 2 * mt * t * e.cy + t * t * e.y2;
      return { x, y };
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(260, Math.max(180, Math.floor(window.innerHeight * 0.3)));
      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);
      buildNetwork();
      // reset training
      epoch = 0;
      phase = "forward";
      phaseT = 0;
      waveLayer = 0;
      lastWaveLayer = -1;
      loss = 2.4;
      lossHistory = [];
      particles = [];
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    const spawnParticlesOnLayerEdges = (fromLayer: number, forward: boolean) => {
      // spawn particles on edges originating (forward) or ending (backward) at fromLayer
      for (let ei = 0; ei < edges.length; ei++) {
        const e = edges[ei];
        const n1 = nodes[e.from];
        const n2 = nodes[e.to];
        if (forward) {
          if (n1.layer !== fromLayer) continue;
          // skip attention edges for forward propagation main flow? include lightly
          if (e.attention) continue;
          // probabilistic spawn based on activation
          if (Math.random() > 0.55) continue;
          particles.push({ edgeIdx: ei, t: 0, speed: 0.5 + Math.random() * 0.5, size: 0.7 + Math.random() * 1.3, forward: true, warm: false });
        } else {
          if (n2.layer !== fromLayer) continue;
          if (e.attention) continue;
          if (Math.random() > 0.55) continue;
          particles.push({ edgeIdx: ei, t: 1, speed: 0.5 + Math.random() * 0.5, size: 0.7 + Math.random() * 1.3, forward: false, warm: true });
        }
      }
      // cap
      if (particles.length > 380) particles.splice(0, particles.length - 380);
    };

    const activateLayer = (l: number, amount: number) => {
      const [s, e] = layerNodeIndexRanges[l];
      for (let i = s; i < e; i++) {
        nodes[i].activation = Math.min(1, nodes[i].activation + amount * (0.5 + Math.random() * 0.5));
        nodes[i].pulse = 1;
      }
    };

    const update = (dt: number) => {
      // phase progression
      const dur = phase === "forward" ? FORWARD_DUR : phase === "backward" ? BACKWARD_DUR : UPDATE_DUR;
      phaseT += dt / dur;
      if (phaseT >= 1) {
        phaseT = 0;
        if (phase === "forward") {
          phase = "backward";
          // start backward wave at last layer
          waveLayer = LAYER_SIZES.length - 1;
          lastWaveLayer = -1;
        } else if (phase === "backward") {
          phase = "update";
        } else {
          phase = "forward";
          epoch += 1;
          waveLayer = 0;
          lastWaveLayer = -1;
          // decay loss
          loss = loss * 0.82 + Math.random() * 0.04;
          if (loss < 0.12) {
            // new training run
            loss = 2.4;
            lossHistory = [];
            // reshuffle target weights
            for (const e of edges) {
              e.targetWeight = (Math.random() * 2 - 1) * 0.8;
            }
          }
          lossHistory.push(loss);
          if (lossHistory.length > maxLossHistory) lossHistory.shift();
        }
      }

      // wave front
      if (phase === "forward") {
        const L = LAYER_SIZES.length;
        const wl = Math.min(L - 1, Math.floor(phaseT * L));
        if (wl !== lastWaveLayer) {
          lastWaveLayer = wl;
          activateLayer(wl, 0.8);
          if (wl < L - 1) spawnParticlesOnLayerEdges(wl, true);
        }
      } else if (phase === "backward") {
        const L = LAYER_SIZES.length;
        const wl = Math.max(0, L - 1 - Math.floor(phaseT * L));
        if (wl !== lastWaveLayer) {
          lastWaveLayer = wl;
          activateLayer(wl, 0.6);
          if (wl > 0) spawnParticlesOnLayerEdges(wl - 1, false); // edges into wl going backward
        }
      } else {
        // update: tween weights toward target
        for (const e of edges) {
          e.weight += (e.targetWeight - e.weight) * Math.min(1, dt * 4);
        }
        // occasionally jiggle targets mid-update to feel alive
      }

      // decay activations & pulses
      for (const n of nodes) {
        n.activation *= Math.max(0, 1 - dt * 1.2);
        n.pulse *= Math.max(0, 1 - dt * 2.5);
      }

      // update particles
      for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        const e = edges[p.edgeIdx];
        // speed scaled inversely with edge length for consistent visual velocity
        const v = p.speed * 180 / Math.max(40, e.len);
        p.t += (p.forward ? 1 : -1) * v * dt;
        if (p.t > 1 || p.t < 0) {
          // arrival: activate target node
          const targetNode = p.forward ? e.to : e.from;
          nodes[targetNode].activation = Math.min(1, nodes[targetNode].activation + 0.25);
          nodes[targetNode].pulse = Math.min(1, nodes[targetNode].pulse + 0.4);
          particles.splice(i, 1);
        }
      }
    };

    const drawNetwork = (t: number) => {
      // edges
      for (const e of edges) {
        const aw = Math.abs(e.weight);
        let alpha = 0.04 + aw * 0.12;
        if (e.residual) alpha *= 0.7;
        if (e.attention) alpha *= 0.5;
        const hue = e.attention ? 280 : e.residual ? 170 : 198;
        const sat = e.attention ? 30 : 28;
        const lum = 50 + aw * 10;
        ctx.strokeStyle = `hsla(${hue}, ${sat}%, ${lum}%, ${alpha})`;
        ctx.lineWidth = (e.residual || e.attention) ? 0.8 : 0.6 + aw * 0.8;
        ctx.beginPath();
        if (e.residual || e.attention) {
          ctx.moveTo(e.x1, e.y1);
          ctx.quadraticCurveTo(e.cx, e.cy, e.x2, e.y2);
        } else {
          ctx.moveTo(e.x1, e.y1);
          ctx.lineTo(e.x2, e.y2);
        }
        ctx.stroke();
      }

      // particles
      for (const p of particles) {
        const e = edges[p.edgeIdx];
        const pt = bezier(e, p.t);
        const hue = p.warm ? 28 : 198;
        const sat = p.warm ? 60 : 35;
        const lum = p.warm ? 62 : 70;
        // glow
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${lum}%, 0.85)`;
        ctx.beginPath();
        ctx.arc(pt.x, pt.y, p.size, 0, Math.PI * 2);
        ctx.fill();
        // halo
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${lum}%, 0.18)`;
        ctx.beginPath();
        ctx.arc(pt.x, pt.y, p.size * 2.4, 0, Math.PI * 2);
        ctx.fill();
      }

      // nodes
      for (const n of nodes) {
        const a = n.activation;
        const pulse = n.pulse;
        const r = 2.2 + a * 2.5 + pulse * 1.5;
        const hue = n.isAttention ? 275 : 198;
        const sat = n.isAttention ? 35 : 32;
        const lum = 45 + a * 30 + pulse * 15;
        // outer glow
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${lum}%, ${0.18 + a * 0.25})`;
        ctx.beginPath();
        ctx.arc(n.x, n.y, r * 3.2, 0, Math.PI * 2);
        ctx.fill();
        // core
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${Math.min(90, lum + 20)}%, ${0.6 + a * 0.4})`;
        ctx.beginPath();
        ctx.arc(n.x, n.y, r, 0, Math.PI * 2);
        ctx.fill();
        // mercury specular
        if (a > 0.3) {
          ctx.fillStyle = `hsla(${n.isAttention ? 280 : 200}, 20%, 96%, ${a * 0.5})`;
          ctx.beginPath();
          ctx.arc(n.x - r * 0.25, n.y - r * 0.25, r * 0.4, 0, Math.PI * 2);
          ctx.fill();
        }
      }

      // loss curve (bottom-right)
      drawLossCurve();
      // epoch label (subtle, top-left)
      ctx.fillStyle = "hsla(198, 20%, 70%, 0.35)";
      ctx.font = "10px ui-monospace, monospace";
      ctx.textBaseline = "top";
      ctx.fillText(`epoch ${epoch.toString().padStart(4, "0")}  loss ${loss.toFixed(3)}`, 12, 8);
    };

    const drawLossCurve = () => {
      const w = 120;
      const h = 36;
      const x0 = width - w - 14;
      const y0 = height - h - 10;
      // panel
      ctx.fillStyle = "hsla(198, 20%, 10%, 0.35)";
      ctx.fillRect(x0, y0, w, h);
      ctx.strokeStyle = "hsla(198, 25%, 40%, 0.4)";
      ctx.lineWidth = 1;
      ctx.strokeRect(x0 + 0.5, y0 + 0.5, w - 1, h - 1);
      // curve
      if (lossHistory.length > 1) {
        ctx.strokeStyle = "hsla(198, 40%, 70%, 0.8)";
        ctx.lineWidth = 1.2;
        ctx.beginPath();
        for (let i = 0; i < lossHistory.length; i++) {
          const px = x0 + (i / (maxLossHistory - 1)) * w;
          const py = y0 + h - Math.min(1, lossHistory[i] / 2.5) * (h - 4) - 2;
          if (i === 0) ctx.moveTo(px, py);
          else ctx.lineTo(px, py);
        }
        ctx.stroke();
      }
      // label
      ctx.fillStyle = "hsla(198, 20%, 70%, 0.5)";
      ctx.font = "8px ui-monospace, monospace";
      ctx.textBaseline = "bottom";
      ctx.fillText("loss", x0 + 4, y0 - 1);
    };

    let lastTime = performance.now();
    const draw = (now: number) => {
      const dt = Math.min(0.05, (now - lastTime) * 0.001);
      lastTime = now;
      const t = (now - start) * 0.001;

      // trail fade
      ctx.fillStyle = "rgba(0, 0, 0, 0.12)";
      ctx.fillRect(0, 0, width, height);

      update(dt);
      drawNetwork(t);

      animationId = requestAnimationFrame(draw);
