          const mx = (e.x1 + e.x2) / 2;
          const my = (e.y1 + e.y2) / 2;
          const drop = height * 0.12;
          e.cx = mx;
          e.cy = my + drop;
        } else {
          e.cx = (e.x1 + e.x2) / 2;
          e.cy = (e.y1 + e.y2) / 2;
        }
      }
    };

    const addEdge = (from: number, to: number, residual: boolean, attention: boolean) => {
      const w = (Math.random() * 2 - 1) * 0.6;
      edges.push({
        from, to,
        weight: w,
        targetWeight: w,
        residual, attention,
        x1: 0, y1: 0, x2: 0, y2: 0, len: 1,
        cx: 0, cy: 0,
      });
    };

    // Quadratic bezier point
    const bezier = (e: Edge, t: number) => {
      const mt = 1 - t;
      const x = mt * mt * e.x1 + 2 * mt * t * e.cx + t * t * e.x2;
      const y = mt * mt * e.y1 + 2 * mt * t * e.cy + t * t * e.y2;
      return { x, y };
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(260, Math.max(180, Math.floor(window.innerHeight * 0.3)));
      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);
      buildNetwork();
      // reset training
      epoch = 0;
      phase = "forward";
      phaseT = 0;
      waveLayer = 0;
      lastWaveLayer = -1;
      loss = 2.4;
      lossHistory = [];
      particles = [];
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    const spawnParticlesOnLayerEdges = (fromLayer: number, forward: boolean) => {
      // spawn particles on edges originating (forward) or ending (backward) at fromLayer
      for (let ei = 0; ei < edges.length; ei++) {
        const e = edges[ei];
        const n1 = nodes[e.from];
        const n2 = nodes[e.to];
        if (forward) {
          if (n1.layer !== fromLayer) continue;
          // skip attention edges for forward propagation main flow? include lightly
          if (e.attention) continue;
          // probabilistic spawn based on activation
          if (Math.random() > 0.55) continue;
          particles.push({ edgeIdx: ei, t: 0, speed: 0.5 + Math.random() * 0.5, size: 0.7 + Math.random() * 1.3, forward: true, warm: false });
        } else {
          if (n2.layer !== fromLayer) continue;
          if (e.attention) continue;
          if (Math.random() > 0.55) continue;
          particles.push({ edgeIdx: ei, t: 1, speed: 0.5 + Math.random() * 0.5, size: 0.7 + Math.random() * 1.3, forward: false, warm: true });
        }
      }
      // cap
      if (particles.length > 380) particles.splice(0, particles.length - 380);
    };

    const activateLayer = (l: number, amount: number) => {
      const [s, e] = layerNodeIndexRanges[l];
      for (let i = s; i < e; i++) {
        nodes[i].activation = Math.min(1, nodes[i].activation + amount * (0.5 + Math.random() * 0.5));
        nodes[i].pulse = 1;
      }
    };

    const update = (dt: number) => {
      // phase progression
      const dur = phase === "forward" ? FORWARD_DUR : phase === "backward" ? BACKWARD_DUR : UPDATE_DUR;
      phaseT += dt / dur;
      if (phaseT >= 1) {
        phaseT = 0;
        if (phase === "forward") {
          phase = "backward";
          // start backward wave at last layer
          waveLayer = LAYER_SIZES.length - 1;
          lastWaveLayer = -1;
        } else if (phase === "backward") {
          phase = "update";
        } else {
          phase = "forward";
          epoch += 1;
          waveLayer = 0;
          lastWaveLayer = -1;
          // decay loss
          loss = loss * 0.82 + Math.random() * 0.04;
          if (loss < 0.12) {
            // new training run
            loss = 2.4;
            lossHistory = [];
            // reshuffle target weights
            for (const e of edges) {
              e.targetWeight = (Math.random() * 2 - 1) * 0.8;
            }
          }
          lossHistory.push(loss);
          if (lossHistory.length > maxLossHistory) lossHistory.shift();
        }
      }

      // wave front
      if (phase === "forward") {
        const L = LAYER_SIZES.length;
        const wl = Math.min(L - 1, Math.floor(phaseT * L));
        if (wl !== lastWaveLayer) {
          lastWaveLayer = wl;
          activateLayer(wl, 0.8);
          if (wl < L - 1) spawnParticlesOnLayerEdges(wl, true);
        }
      } else if (phase === "backward") {
        const L = LAYER_SIZES.length;
        const wl = Math.max(0, L - 1 - Math.floor(phaseT * L));
        if (wl !== lastWaveLayer) {
          lastWaveLayer = wl;
          activateLayer(wl, 0.6);
          if (wl > 0) spawnParticlesOnLayerEdges(wl - 1, false); // edges into wl going backward
        }
      } else {
        // update: tween weights toward target
        for (const e of edges) {
          e.weight += (e.targetWeight - e.weight) * Math.min(1, dt * 4);
        }
        // occasionally jiggle targets mid-update to feel alive
      }

      // decay activations & pulses
      for (const n of nodes) {
        n.activation *= Math.max(0, 1 - dt * 1.2);
        n.pulse *= Math.max(0, 1 - dt * 2.5);
      }

      // update particles
      for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        const e = edges[p.edgeIdx];
        // speed scaled inversely with edge length for consistent visual velocity
        const v = p.speed * 180 / Math.max(40, e.len);
        p.t += (p.forward ? 1 : -1) * v * dt;
        if (p.t > 1 || p.t < 0) {
          // arrival: activate target node
          const targetNode = p.forward ? e.to : e.from;
          nodes[targetNode].activation = Math.min(1, nodes[targetNode].activation + 0.25);
          nodes[targetNode].pulse = Math.min(1, nodes[targetNode].pulse + 0.4);
          particles.splice(i, 1);
        }
      }
    };

