      // edges
      for (const e of edges) {
        const aw = Math.abs(e.weight);
        let alpha = 0.04 + aw * 0.12;
        if (e.residual) alpha *= 0.7;
        if (e.attention) alpha *= 0.5;
        const hue = e.attention ? 280 : e.residual ? 170 : 198;
        const sat = e.attention ? 30 : 28;
        const lum = 50 + aw * 10;
        ctx.strokeStyle = `hsla(${hue}, ${sat}%, ${lum}%, ${alpha})`;
        ctx.lineWidth = (e.residual || e.attention) ? 0.8 : 0.6 + aw * 0.8;
        ctx.beginPath();
        if (e.residual || e.attention) {
          ctx.moveTo(e.x1, e.y1);
          ctx.quadraticCurveTo(e.cx, e.cy, e.x2, e.y2);
        } else {
          ctx.moveTo(e.x1, e.y1);
          ctx.lineTo(e.x2, e.y2);
        }
        ctx.stroke();
      }

      // particles
      for (const p of particles) {
        const e = edges[p.edgeIdx];
        const pt = bezier(e, p.t);
        const hue = p.warm ? 28 : 198;
        const sat = p.warm ? 60 : 35;
        const lum = p.warm ? 62 : 70;
        // glow
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${lum}%, 0.85)`;
        ctx.beginPath();
        ctx.arc(pt.x, pt.y, p.size, 0, Math.PI * 2);
        ctx.fill();
        // halo
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${lum}%, 0.18)`;
        ctx.beginPath();
        ctx.arc(pt.x, pt.y, p.size * 2.4, 0, Math.PI * 2);
        ctx.fill();
      }

      // nodes
      for (const n of nodes) {
        const a = n.activation;
        const pulse = n.pulse;
        const r = 2.2 + a * 2.5 + pulse * 1.5;
        const hue = n.isAttention ? 275 : 198;
        const sat = n.isAttention ? 35 : 32;
        const lum = 45 + a * 30 + pulse * 15;
        // outer glow
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${lum}%, ${0.18 + a * 0.25})`;
        ctx.beginPath();
        ctx.arc(n.x, n.y, r * 3.2, 0, Math.PI * 2);
        ctx.fill();
        // core
        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${Math.min(90, lum + 20)}%, ${0.6 + a * 0.4})`;
        ctx.beginPath();
        ctx.arc(n.x, n.y, r, 0, Math.PI * 2);
        ctx.fill();
        // mercury specular
        if (a > 0.3) {
          ctx.fillStyle = `hsla(${n.isAttention ? 280 : 200}, 20%, 96%, ${a * 0.5})`;
          ctx.beginPath();
          ctx.arc(n.x - r * 0.25, n.y - r * 0.25, r * 0.4, 0, Math.PI * 2);
          ctx.fill();
        }
      }

      // loss curve (bottom-right)
      drawLossCurve();
      // epoch label (subtle, top-left)
      ctx.fillStyle = "hsla(198, 20%, 70%, 0.35)";
      ctx.font = "10px ui-monospace, monospace";
      ctx.textBaseline = "top";
      ctx.fillText(`epoch ${epoch.toString().padStart(4, "0")}  loss ${loss.toFixed(3)}`, 12, 8);
    };

    const drawLossCurve = () => {
      const w = 120;
      const h = 36;
      const x0 = width - w - 14;
      const y0 = height - h - 10;
      // panel
      ctx.fillStyle = "hsla(198, 20%, 10%, 0.35)";
      ctx.fillRect(x0, y0, w, h);
      ctx.strokeStyle = "hsla(198, 25%, 40%, 0.4)";
      ctx.lineWidth = 1;
      ctx.strokeRect(x0 + 0.5, y0 + 0.5, w - 1, h - 1);
      // curve
      if (lossHistory.length > 1) {
        ctx.strokeStyle = "hsla(198, 40%, 70%, 0.8)";
        ctx.lineWidth = 1.2;
        ctx.beginPath();
        for (let i = 0; i < lossHistory.length; i++) {
          const px = x0 + (i / (maxLossHistory - 1)) * w;
          const py = y0 + h - Math.min(1, lossHistory[i] / 2.5) * (h - 4) - 2;
          if (i === 0) ctx.moveTo(px, py);
          else ctx.lineTo(px, py);
        }
        ctx.stroke();
      }
      // label
      ctx.fillStyle = "hsla(198, 20%, 70%, 0.5)";
      ctx.font = "8px ui-monospace, monospace";
      ctx.textBaseline = "bottom";
      ctx.fillText("loss", x0 + 4, y0 - 1);
    };

    let lastTime = performance.now();
    const draw = (now: number) => {
      const dt = Math.min(0.05, (now - lastTime) * 0.001);
      lastTime = now;
      const t = (now - start) * 0.001;

      // trail fade
      ctx.fillStyle = "rgba(0, 0, 0, 0.12)";
      ctx.fillRect(0, 0, width, height);

      update(dt);
      drawNetwork(t);

      animationId = requestAnimationFrame(draw);
    };

    resize();
    start = performance.now();
    lastTime = performance.now();
    window.addEventListener("resize", debouncedResize);
    animationId = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener("resize", debouncedResize);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed inset-x-0 top-0 z-0"
      style={{ display: "block" }}
    );
  }
}
