```typescript
"use client";

import { useEffect, useRef } from "react";

interface NetNode {
  layer: number;
  idx: number;
  x: number;
  y: number;
  act: number;  // forward activation 0..1
  grad: number; // backward gradient 0..1
}

interface NetEdge {
  a: NetNode;
  b: NetNode;
  w: number;       // current weight -1..1
  tw: number;      // target weight
  skip: boolean;
}

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;
    let start = performance.now();

    // Architecture: ResMLP with two residual blocks
    const LAYER_SIZES = [5, 7, 7, 7, 5, 3];
    const NUM_LAYERS = LAYER_SIZES.length;
    // residual skips: from -> to (to = from + 2)
    const SKIPS = [[0, 2], [2, 4]];

    let nodes: NetNode[][] = [];
    let edges: NetEdge[] = [];
    let skipEdges: NetEdge[] = [];

    // Training state
    let epoch = 0;
    let loss = 2.4;
    let lossHistory: number[] = [];
    let runStart = performance.now();
    const FORWARD_DUR = 1.1;
    const BACKWARD_DUR = 1.1;
    const UPDATE_DUR = 0.45;
    const CYCLE_DUR = FORWARD_DUR + BACKWARD_DUR + UPDATE_DUR;

    const randn = () => (Math.random() + Math.random() + Math.random() - 1.5) * 0.5;

    const buildNetwork = () => {
      nodes = [];
      edges = [];
      skipEdges = [];

      const marginX = Math.max(60, width * 0.06);
      const availW = width - marginX * 2;
      const spacingX = availW / (NUM_LAYERS - 1);

      const cy = height * 0.46;
      const availH = height * 0.78;
      const maxNodes = Math.max(...LAYER_SIZES);
      const spacingY = Math.min(26, availH / (maxNodes - 1));

      for (let l = 0; l < NUM_LAYERS; l++) {
        const n = LAYER_SIZES[l];
        const layerNodes: NetNode[] = [];
        const x = marginX + l * spacingX;
        for (let i = 0; i < n; i++) {
          const y = cy - ((n - 1) / 2) * spacingY + i * spacingY;
          layerNodes.push({ layer: l, idx: i, x, y, act: 0, grad: 0 });
        }
        nodes.push(layerNodes);
      }

      // sequential edges
      for (let l = 0; l < NUM_LAYERS - 1; l++) {
        for (const a of nodes[l]) {
          for (const b of nodes[l + 1]) {
            const w = randn() * 0.5;
            edges.push({ a, b, w, tw: w, skip: false });
          }
        }
      }

      // skip (residual) edges
      for (const [from, to] of SKIPS) {
        for (const a of nodes[from]) {
          for (const b of nodes[to]) {
            const w = randn() * 0.35;
            skipEdges.push({ a, b, w, tw: w, skip: true });
          }
        }
      }
    };

    const resetRun = () => {
      // new training run: re-init target weights, reset loss
      for (const e of edges) e.tw = randn() * 0.5;
      for (const e of skipEdges) e.tw = randn() * 0.35;
      epoch = 0;
      loss = 2.3 + Math.random() * 0.3;
      lossHistory = [];
      runStart = performance.now();
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(300, Math.max(200, Math.floor(window.innerHeight * 0.32)));
      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);
      buildNetwork();
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    const TAU = Math.PI * 2;

    const draw = (now: number) => {
      const t = (now - start) * 0.001;
      const rt = (now - runStart) * 0.001;

      // determine phase
      const cycleTime = rt % CYCLE_DUR;
      let phase: "fwd" | "bwd" | "upd";
      let phaseT = 0;
      if (cycleTime < FORWARD_DUR) {
        phase = "fwd";
        phaseT = cycleTime / FORWARD_DUR;
      } else if (cycleTime < FORWARD_DUR + BACKWARD_DUR) {
        phase = "bwd";
        phaseT = (cycleTime - FORWARD_DUR) / BACKWARD_DUR;
      } else {
        phase = "upd";
        phaseT = (cycleTime - FORWARD_DUR - BACKWARD_DUR) / UPDATE_DUR;
      }

      // epoch increments at start of each cycle
      const curEpoch = Math.floor(rt / CYCLE_DUR);
      if (curEpoch !== epoch) {
        epoch = curEpoch;
        // loss decreases
        loss = Math.max(0.05, loss * 0.88 + Math.random() * 0.06 - 0.02);
        lossHistory.push(loss);
        if (lossHistory.length > 120) lossHistory.shift();
        // evolve target weights slightly (drift)
        for (const e of edges) e.tw += (Math.random() - 0.5) * 0.04;
        for (const e of skipEdges) e.tw += (Math.random() - 0.5) * 0.03;
        // reset run when converged
        if (loss < 0.12 && epoch > 24) {
          resetRun();
        }
      }

      // update weights toward target (during update phase, faster)
      const updateRate = phase === "upd" ? 0.08 : 0.012;
      for (const e of edges) e.w += (e.tw - e.w) * updateRate;
      for (const e of skipEdges) e.w += (e.tw - e.w) * updateRate;

      // compute sweep position
      let sweepPos = 0;
      let sweepDir = 1;
      if (phase === "fwd") {
        sweepPos = phaseT * (NUM_LAYERS - 1);
        sweepDir = 1;
      } else if (phase === "bwd") {
        sweepPos = (1 - phaseT) * (NUM_LAYERS - 1);
        sweepDir = -1;
      } else {
        sweepPos = 0;
      }

      // update node activations/gradients
      for (let l = 0; l < NUM_LAYERS; l++) {
        const dist = Math.abs(sweepPos - l);
        const bump = Math.exp(-(dist * dist) / 0.45);
        for (const n of nodes[l]) {
          if (phase === "fwd") {
            n.act = Math.max(n.act * 0.9, bump);
            n.grad *= 0.9;
          } else if (phase === "bwd") {
            n.grad = Math.max(n.grad * 0.9, bump);
            n.act *= 0.9;
          } else {
            n.act *= 0.86;
            n.grad *= 0.86;
          }
