      ctx.fillStyle = "rgba(0, 0, 0, 0.22)";
      ctx.fillRect(0, 0, width, height);

      // Draw edges (sequential)
      for (const e of edges) {
        const mag = Math.abs(e.w);
        const a = e.a;
        const b = e.b;
        // base alpha from weight magnitude
        let alpha = 0.05 + mag * 0.22;
        // active highlight when sweep between a.layer and b.layer
        const lo = Math.min(a.layer, b.layer);
        const hi = Math.max(a.layer, b.layer);
        const inSweep = sweepPos >= lo - 0.1 && sweepPos <= hi + 0.1 && (phase === "fwd" || phase === "bwd");
        if (inSweep) {
          const edgeProgress = Math.max(0, Math.min(1, sweepPos - lo)); // 0..1 across edge
          const proximity = Math.sin(Math.min(1, Math.max(0, 1 - Math.abs(edgeProgress - 0.5) * 2)) * Math.PI * 0.5);
          alpha += proximity * 0.5 * (phase === "fwd" ? 1 : 0.8);
        }
        const sign = e.w >= 0 ? 1 : -1;
        const hue = phase === "bwd" && inSweep ? 320 : (sign > 0 ? 198 : 16);
        const sat = phase === "bwd" && inSweep ? 60 : 30;
        ctx.strokeStyle = `hsla(${hue}, ${sat}%, 62%, ${alpha})`;
        ctx.lineWidth = 0.5 + mag * 1.2;
        ctx.beginPath();
        ctx.moveTo(a.x, a.y);
        ctx.lineTo(b.x, b.y);
        ctx.stroke();

        // traveling pulse on active edge
        if (inSweep && (phase === "fwd" || phase === "bwd")) {
          const edgeProgress = Math.max(0, Math.min(1, sweepPos - lo));
          const pdir = phase === "fwd" ? edgeProgress : 1 - edgeProgress;
          const px = a.x + (b.x - a.x) * pdir;
          const py = a.y + (b.y - a.y) * pdir;
          const pulseHue = phase === "fwd" ? 190 : 320;
          ctx.fillStyle = `hsla(${pulseHue}, 80%, 75%, 0.9)`;
          ctx.beginPath();
          ctx.arc(px, py, 1.6, 0, TAU);
          ctx.fill();
        }
      }

      // Draw skip (residual) edges as arcs
      for (const e of skipEdges) {
        const a = e.a;
        const b = e.b;
        const mag = Math.abs(e.w);
        const midX = (a.x + b.x) / 2;
        const arcH = 34 + Math.abs(a.idx - b.idx) * 2;
        const ctrlX = midX;
        const ctrlY = Math.min(a.y, b.y) - arcH;
        let alpha = 0.06 + mag * 0.2;
        const inSweep = sweepPos >= a.layer - 0.1 && sweepPos <= b.layer + 0.1 && (phase === "fwd" || phase === "bwd");
        if (inSweep) {
          alpha += 0.3 * (phase === "fwd" ? 1 : 0.7);
        }
        ctx.strokeStyle = `hsla(170, 45%, 60%, ${alpha})`;
        ctx.lineWidth = 0.5 + mag * 1.0;
        ctx.setLineDash([3, 4]);
        ctx.beginPath();
        ctx.moveTo(a.x, a.y);
        ctx.quadraticCurveTo(ctrlX, ctrlY, b.x, b.y);
        ctx.stroke();
        ctx.setLineDash([]);

        // pulse along arc
        if (inSweep && (phase === "fwd" || phase === "bwd")) {
          const edgeProgress = Math.max(0, Math.min(1, (sweepPos - a.layer) / (b.layer - a.layer)));
          const pdir = phase === "fwd" ? edgeProgress : 1 - edgeProgress;
          // quadratic bezier point
          const px = (1 - pdir) * (1 - pdir) * a.x + 2 * (1 - pdir) * pdir * ctrlX + pdir * pdir * b.x;
          const py = (1 - pdir) * (1 - pdir) * a.y + 2 * (1 - pdir) * pdir * ctrlY + pdir * pdir * b.y;
          ctx.fillStyle = `hsla(170, 80%, 72%, 0.85)`;
          ctx.beginPath();
          ctx.arc(px, py, 1.5, 0, TAU);
          ctx.fill();
        }
      }

      // Draw nodes
      for (let l = 0; l < NUM_LAYERS; l++) {
        for (const n of nodes[l]) {
          const isInput = l === 0;
          const isOutput = l === NUM_LAYERS - 1;
          const baseR = isInput || isOutput ? 3.2 : 2.6;
          const glow = Math.max(n.act, n.grad);
          const r = baseR + glow * 2.4;

          // glow halo
          if (glow > 0.05) {
            const hue = n.grad > n.act ? 320 : 190;
            ctx.fillStyle = `hsla(${hue}, 70%, 60%, ${glow * 0.25})`;
            ctx.beginPath();
            ctx.arc(n.x, n.y, r * 3.5, 0, TAU);
            ctx.fill();
          }

          // core
          const coreHue = n.grad > n.act ? 322 : 196;
          const coreLum = 60 + glow * 30;
          ctx.fillStyle = `hsla(${coreHue}, 55%, ${coreLum}%, ${0.85})`;
          ctx.beginPath();
          ctx.arc(n.x, n.y, r, 0, TAU);
          ctx.fill();

          // bright center
          if (glow > 0.2) {
            ctx.fillStyle = `hsla(${coreHue + 10}, 30%, 95%, ${glow * 0.7})`;
            ctx.beginPath();
            ctx.arc(n.x, n.y, r * 0.45, 0, TAU);
            ctx.fill();
          }
        }
      }

      // Loss curve (bottom-left)
      const gx = 14;
      const gy = height - 14;
      const gw = 120;
      const gh = 40;
      ctx.strokeStyle = "rgba(120, 160, 200, 0.25)";
      ctx.lineWidth = 1;
      ctx.strokeRect(gx, gy - gh, gw, gh);

      if (lossHistory.length > 1) {
        ctx.strokeStyle = "hsla(190, 70%, 65%, 0.9)";
        ctx.lineWidth = 1.2;
        ctx.beginPath();
        for (let i = 0; i < lossHistory.length; i++) {
          const px = gx + (i / Math.max(1, lossHistory.length - 1)) * gw;
          const py = gy - (lossHistory[i] / 2.6) * gh;
          if (i === 0) ctx.moveTo(px, py);
          else ctx.lineTo(px, py);
        }
        ctx.stroke();
      }

      // labels
      ctx.fillStyle = "rgba(150, 180, 210, 0.5)";
      ctx.font = "9px ui-monospace, monospace";
      ctx.fillText(`loss ${loss.toFixed(3)}`, gx + 4, gy - gh - 4);
      ctx.fillText(`epoch ${epoch}`, gx + gw - 52, gy - gh - 4);

      // phase label
      const phaseLabel = phase === "fwd" ? "forward" : phase === "bwd" ? "backward" : "update";
      const phaseHue = phase === "fwd" ? 190 : phase === "bwd" ? 320 : 170;
      ctx.fillStyle = `hsla(${phaseHue}, 60%, 70%, 0.55)`;
      ctx.fillText(phaseLabel, width - 80, 16);

      animationId = requestAnimationFrame(draw);
    };

    resize();
    start = performance.now();
    runStart = start;
    resetRun();
    window.addEventListener("resize", debouncedResize);
    animationId = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener("resize", debouncedResize);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed inset-x-0 top-0 z-0"
      style={{ display: "block" }}
    />
  );
}
