  const c = document.querySelector('canvas');
  if (!c) return { ok: false, reason: 'no canvas' };
  const ctx = c.getContext('2d');
  // sample center pixel alpha to confirm something was drawn
  const w = c.width, h = c.height;
  const data = ctx.getImageData(Math.floor(w*0.5), Math.floor(h*0.4), 1, 1).data;
  // count non-black pixels in a strip
  let nonBlack = 0;
  const strip = ctx.getImageData(0, 0, w, Math.min(h, 120));
  for (let i = 0; i < strip.data.length; i += 4) {
    if (strip.data[i] + strip.data[i+1] + strip.data[i+2] > 30) nonBlack++;
  }
  return {
    ok: true,
    width: w,
    height: h,
    samplePixel: [data[0], data[1], data[2], data[3]],
    nonBlackPixels: nonBlack,
  };
}

