        ctx.moveTo(a.x, a.y);
        ctx.lineTo(b.x, b.y);
        ctx.stroke();

        if (sweeping) {
          const edgeProgress = Math.max(0, Math.min(1, sweepPos - lo));
          const p = phase === "fwd" ? edgeProgress : 1 - edgeProgress;
          const px = a.x + (b.x - a.x) * p;
          const py = a.y + (b.y - a.y) * p;
          fillCircle(px, py, 1.4, pulseColor, 0.7);
        }
      }

      // skip (residual) edges as arced dashed links
      ctx.setLineDash(DASH);
      for (const e of edges) {
        if (!e.skip) continue;
        const a = e.a;
        const b = e.b;
        const lo = a.layer;
        const hi = b.layer;
        const mag = Math.abs(e.w);
        const sweeping = isSweeping && sweepPos >= lo - 0.1 && sweepPos <= hi + 0.1;

        let alpha = 0.05 + mag * 0.13 + updateGlow * 0.08;
        if (sweeping) alpha += 0.16;

        const midX = (a.x + b.x) / 2;
        const arcH = 30 + Math.abs(a.idx - b.idx) * 2.5;
        const ctrlX = midX;
        const ctrlY = Math.min(a.y, b.y) - arcH;

        ctx.globalAlpha = alpha;
        ctx.strokeStyle = C.skip;
        ctx.lineWidth = 0.45 + mag * 0.8;
        ctx.beginPath();
        ctx.moveTo(a.x, a.y);
        ctx.quadraticCurveTo(ctrlX, ctrlY, b.x, b.y);
        ctx.stroke();

        if (sweeping) {
          const span = hi - lo;
          const edgeProgress = Math.max(0, Math.min(1, (sweepPos - lo) / span));
          const p = phase === "fwd" ? edgeProgress : 1 - edgeProgress;
