          const py = (1 - p) * (1 - p) * a.y + 2 * (1 - p) * p * ctrlY + p * p * b.y;
          fillCircle(px, py, 1.3, C.pulseSkip, 0.65);
        }
      }
      ctx.setLineDash([]);

      // nodes
      for (let l = 0; l < NUM_LAYERS; l++) {
        for (const n of nodes[l]) {
          const isEdgeLayer = l === 0 || l === NUM_LAYERS - 1;
          const baseR = isEdgeLayer ? 3.0 : 2.4;
          const inputBoost = l === 0 ? n.pat * 0.4 : 0;
          const glow = Math.max(n.act, n.grad, inputBoost);
          const r = baseR + glow * 1.8;

