"use client";

import { useEffect, useRef } from "react";

interface NetNode {
  layer: number;
  idx: number;
  x: number;
  y: number;
  act: number;
  grad: number;
  pat: number;
}

interface NetEdge {
  a: NetNode;
  b: NetNode;
  w: number;
  tw: number;
  skip: boolean;
}

// ResMLP: two residual blocks. Slightly more complex than a plain MLP,
// with skip connections drawn as arced dashed links.
const LAYER_SIZES = [5, 7, 7, 7, 5, 3];
const NUM_LAYERS = LAYER_SIZES.length;
const SKIPS: Array<[number, number]> = [
  [0, 2],
  [2, 4],
];

// Solid colors (alpha controlled via ctx.globalAlpha) — avoids per-frame
// hsla string allocations in the hot draw loop.
const C = {
  fwd: "hsl(198, 38%, 56%)",
  bwd: "hsl(322, 38%, 56%)",
  skip: "hsl(168, 32%, 56%)",
  neg: "hsl(16, 38%, 56%)",
  nodeFwd: "hsl(196, 34%, 62%)",
  nodeBwd: "hsl(322, 34%, 62%)",
  pulseFwd: "hsl(190, 50%, 72%)",
  pulseBwd: "hsl(322, 50%, 72%)",
  pulseSkip: "hsl(168, 50%, 72%)",
};
const DASH = [3, 4];
const TAU = Math.PI * 2;

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;

    let nodes: NetNode[][] = [];
    let edges: NetEdge[] = [];
    let runStart = performance.now();
    let nextReset = 26 + Math.random() * 12;
    let cycle = 0;

    const FORWARD_DUR = 0.95;
    const BACKWARD_DUR = 0.95;
    const UPDATE_DUR = 0.38;
    const CYCLE_DUR = FORWARD_DUR + BACKWARD_DUR + UPDATE_DUR;

    const randn = () =>
      (Math.random() + Math.random() + Math.random() - 1.5) * 0.5;

    const buildNetwork = () => {
      nodes = [];
      edges = [];

      const marginX = Math.max(140, Math.min(220, width * 0.08));
      const availW = width - marginX * 2;
      const spacingX = availW / (NUM_LAYERS - 1);

      const cy = height * 0.47;
      const availH = height * 0.8;
      const maxNodes = Math.max(...LAYER_SIZES);
      const spacingY = Math.min(26, availH / (maxNodes - 1));

      for (let l = 0; l < NUM_LAYERS; l++) {
        const n = LAYER_SIZES[l];
        const layerNodes: NetNode[] = [];
        const x = marginX + l * spacingX;
        for (let i = 0; i < n; i++) {
          const y = cy - ((n - 1) / 2) * spacingY + i * spacingY;
          layerNodes.push({ layer: l, idx: i, x, y, act: 0, grad: 0, pat: 0 });
        }
        nodes.push(layerNodes);
      }

      const addEdges = (from: number, to: number, scale: number, skip: boolean) => {
        for (const a of nodes[from]) {
          for (const b of nodes[to]) {
            const w = randn() * scale;
            edges.push({ a, b, w, tw: w, skip });
          }
        }
      };

      for (let l = 0; l < NUM_LAYERS - 1; l++) addEdges(l, l + 1, 0.5, false);
      for (const [from, to] of SKIPS) addEdges(from, to, 0.35, true);
    };

    const resetRun = () => {
      for (const e of edges) e.tw = randn() * (e.skip ? 0.35 : 0.5);
      runStart = performance.now();
      nextReset = 26 + Math.random() * 12;
      cycle = 0;
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(300, Math.max(200, Math.floor(window.innerHeight * 0.32)));
      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);
      buildNetwork();
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    const fillCircle = (x: number, y: number, r: number, color: string, alpha: number) => {
      ctx.globalAlpha = alpha;
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.arc(x, y, r, 0, TAU);
      ctx.fill();
    };

    const draw = (now: number) => {
      const rt = (now - runStart) * 0.001;
      if (rt > nextReset) resetRun();

      const cycleTime = rt % CYCLE_DUR;
      let phase: "fwd" | "bwd" | "upd" = "fwd";
      let phaseT = 0;
      if (cycleTime < FORWARD_DUR) {
        phase = "fwd";
        phaseT = cycleTime / FORWARD_DUR;
      } else if (cycleTime < FORWARD_DUR + BACKWARD_DUR) {
        phase = "bwd";
        phaseT = (cycleTime - FORWARD_DUR) / BACKWARD_DUR;
      } else {
        phase = "upd";
        phaseT = (cycleTime - FORWARD_DUR - BACKWARD_DUR) / UPDATE_DUR;
      }

