() => {
  const c = document.querySelector('canvas');
  if (!c) return { ok: false };
  const ctx = c.getContext('2d');
  const w = c.width, h = c.height;
  let nonBlack = 0, bright = 0;
  const strip = ctx.getImageData(0, 0, w, Math.min(h, 300));
  for (let i = 0; i < strip.data.length; i += 4) {
    const sum = strip.data[i] + strip.data[i+1] + strip.data[i+2];
    if (sum > 30) nonBlack++;
    if (sum > 400) bright++;
  }
  return { ok: true, w, h, nonBlack, bright };
}

